patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..c8e09d29b460 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4827,8 +4827,29 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
                               ConstantExpr::getNeg(RHSC));
   }

+  }
+
   if (Instruction * R = foldICmpXorXX(I, Q, *this))
     return R;
+
+  // (icmp slt/sgt (~a ^ b), ~a) -> (icmp sgt/slt (a ^ b), a)
+  // This folds patterns like (~a ^ b) < ~a into (a ^ b) > a.
+  // Since xor is commutative, we need to check different operand orders.
+  {
+    ICmpInst::Predicate Pred = I.getPredicate();
+    if ((Pred == ICmpInst::ICMP_SLT || Pred == ICmpInst::ICMP_SGT) &&
+        BO0 && BO0->getOpcode() == Instruction::Xor && BO0->hasOneUse()) {
+      Value *XorOp1 = BO0->getOperand(1);
+      // If XorOp1 is the RHS, we have (~a ^ b) cmp ~a pattern
+      if (XorOp1 == Op1 && match(BO0->getOperand(0),
+              m_OneUse(m_Xor(m_Value(A), m_AllOnes())))) {
+        // (icmp slt/sgt (~a ^ b), ~a) -> (icmp sgt/slt (a ^ b), a)
+        Value *NewXor = Builder.CreateXor(A, XorOp1);
+        return new ICmpInst(I.getSwappedPredicate(), NewXor, A);
+      }
+    }
+  }
+
   if (Instruction *R = foldICmpOrXX(I, Q, *this))
     return R;

